using namespace std;using ll = long long;int main() {if(1){freopen("angry.in", "r", stdin);freopen("angry.out", "w", stdout);}int N;cin >> N;vector<int> pos(N);for (int i = 0; i < N; i++) cin >> pos[i];sort(pos.begin(), pos.end());int l = 0, r = 2e9, ans = 2e9;while (l <= r) {int mid = (l + r) / 2;double R = mid / 10.0;bool possible = false;for (int start = 0; start < N; start++) {int left = start, right = start;double radius = R;while (radius > 0) {int newLeft = left;while (newLeft > 0 && pos[left] - pos[newLeft - 1] <= radius) {newLeft--;}int newRight = right;while (newRight < N - 1 && pos[newRight + 1] - pos[right] <= radius) {newRight++;}if (newLeft == left && newRight == right) break;left = newLeft;right = newRight;radius -= 1.0;}if (left == 0 && right == N - 1) {possible = true;break;}}if (possible) {ans = mid;r = mid - 1;} else {l = mid + 1;}}cout << fixed << setprecision(1) << ans / 10.0 << '\n';return 0;}//
